class Solution {
    public int findNumberOfLIS(int[] nums) {
        int n = nums.length;
        int[] lengths = new int[n];
        int[] counts = new int[n];

        for (int i = 0; i < n; i++) {
            lengths[i] = 1;
            counts[i] = 1;
        }

        for (int i = 0; i < n; i++) {
            for (int j = 0; j < i; j++) {
                if (nums[i] > nums[j]) {
                    int possibleLength = lengths[j] + 1;
                    if (possibleLength > lengths[i]) {
                        lengths[i] = possibleLength;
                        counts[i] = counts[j];
                    } else if (possibleLength == lengths[i]) {
                        counts[i] += counts[j];
                    }
                }
            }
        }

        int max_length = 0;
        for (int len : lengths) {
            if (len > max_length) {
                max_length = len;
            }
        }

        int result = 0;
        for (int i = 0; i < n; i++) {
            if (lengths[i] == max_length) {
                result += counts[i];
            }
        }

        return result;
    }
}

